import dataclasses

from cuda.tile._ir.ir import Block, Operation, Var
from cuda.tile._ir.ops import AssumeDivBy, MakeTensorView, LoadPointer, StorePointer
from cuda.tile._passes.dataflow_analysis import DataflowResult, DataPredicate

_OPS_NEED_ASSUME = (MakeTensorView, LoadPointer, StorePointer)


def add_divby_pass(root_block: Block, df_result: DataflowResult):
    candidates = set()
    _scan_block(root_block, candidates)
    var_map = {}
    _rewrite_block(root_block, df_result, var_map, candidates)


def _scan_block(block: Block, candidates: set[str]):
    """Add var that needs divby to candidates"""
    for op in block:
        if isinstance(op, _OPS_NEED_ASSUME):
            for var in op.all_inputs():
                candidates.add(var.name)
        for b in op.nested_blocks:
            _scan_block(b, candidates)


def _rewrite_block(block: Block,
                   df_result: DataflowResult,
                   var_map: dict[str, Var],
                   candidates: set[str]):
    new_ops = []
    for param in block.params:
        _add_assume_divby(param, df_result, new_ops, var_map)

    for op in block:
        to_assume = tuple(var for var in op.result_vars if var.name in candidates)
        new_ops.append(_remap_operands(op, var_map))
        for var in to_assume:
            _add_assume_divby(var, df_result, new_ops, var_map)
        for b in op.nested_blocks:
            _rewrite_block(b, df_result, var_map, candidates)

    block[:] = new_ops


def _remap_operands(op: Operation, var_map: dict[str, Var]):
    new_fields = {}
    for field_name, var in op.operands.items():
        if isinstance(var, tuple):
            new_var = tuple(var_map.get(vi.name, vi) for vi in var)
            new_fields[field_name] = new_var
        elif isinstance(var, Var):
            new_var = var_map.get(var.name, var)
            new_fields[field_name] = new_var
    return dataclasses.replace(op, **new_fields)


def _add_assume_divby(x: Var,
                      df_result: DataflowResult,
                      op_list: list[Operation],
                      var_map: dict[str, Var]) -> Var:
    if x.name in var_map:
        return x
    MAX_DIVBY = 1024
    divisor = df_result[x.name].div_by
    power_of_2_d = min(divisor & -divisor, MAX_DIVBY)
    if power_of_2_d > 1:
        result_var = x.ctx.make_var_like(x)
        result_var.set_type(x.get_type())
        op = AssumeDivBy(divisor=power_of_2_d,
                         x=x,
                         result_vars=(result_var,), loc=x.loc)
        op_list.append(op)
        var_map[x.name] = result_var
        old_pred = df_result[x.name]
        df_result.predicates[result_var.name] = DataPredicate(
            alias_set=old_pred.alias_set,
            div_by=power_of_2_d,
            may_alias_internally=old_pred.may_alias_internally
            )
        return result_var
    return x

@impl(ct.bid)
def bid_impl(axis: Var) -> Var:
    axis = require_constant_int(axis)
    return bid(axis)


@dataclass(eq=False)
class MakeTensorView(Operation, opcode="make_tensor_view"):
    base_ptr: Var = operand()
    shape: tuple[Var, ...] = operand()
    dynamic_strides: tuple[Var, ...] = operand()

    @override
    def generate_bytecode(self, ctx: BytecodeContext) -> bc.Value:
        array_ty: ArrayTy = self.result_var.get_type()
        view_type_id = tensor_view_typeid(ctx.type_table, array_ty)
        base_ptr = ctx.get_value(self.base_ptr)
        shape = tuple(ctx.get_value(x) for x in self.shape)
        dynamic_strides = tuple(ctx.get_value(x) for x in self.dynamic_strides)
        return bc.encode_MakeTensorViewOp(ctx.builder,
                                          result_type=view_type_id,
                                          base=base_ptr,
                                          dynamicShape=shape,
                                          dynamicStrides=dynamic_strides)


@dataclass(eq=False)
class AssumeDivBy(Operation, opcode="assume_div_by"):
    divisor: int = attribute()
    x: Var = operand()

    @override
    def generate_bytecode(self, ctx: BytecodeContext) -> bc.Value:
        x = ctx.get_value(self.x)
        type_id = ctx.typeid_of(self.result_var)
        return bc.encode_AssumeOp(ctx.builder, type_id, x, bc.DivBy(self.divisor))


def assume_div_by(x: Var, divisor: int | None) -> Var:
    if divisor is None or divisor == 1 or CUDA_TILE_TESTING_DISABLE_DIV:
        return x
    if x.is_constant():
        val = x.get_constant()
        if val % divisor != 0:
            raise TileTypeError(
                f"Value {val} is not divisible by {divisor}: "
                f"`assume_divisible_by` contradicts a known constant")
        return x
    return add_operation(AssumeDivBy, x.get_type(), x=x, divisor=divisor)


@impl(ct.assume_divisible_by)
def assume_divisible_by_impl(x: Var, divisor: Var) -> Var:
    ty = x.get_type()
    if not is_scalar(ty, is_integral):
        raise TileTypeError(
            f"`assume_divisible_by` requires an integer scalar, got {ty}")
    divisor_val = require_constant_int(divisor)
    if divisor_val < 1:
        raise TileTypeError(
            f"`assume_divisible_by` requires a positive divisor, got {divisor_val}")
    return assume_div_by(x, divisor_val)


@dataclass(eq=False)
class AssumeBounded(Operation, opcode="assume_bounded"):
    lower_bound: int | None = attribute()
    upper_bound: int | None = attribute()
    x: Var = operand()

    @override
    def generate_bytecode(self, ctx: BytecodeContext) -> bc.Value:
        x = ctx.get_value(self.x)
        type_id = ctx.typeid_of(self.result_var)
        pred = bc.Bounded(lb=self.lower_bound, ub=self.upper_bound)
        return bc.encode_AssumeOp(ctx.builder, type_id, x, pred)


def assume_bounded(x: Var, lower_bound: int | None, upper_bound: int | None) -> Var:
    return add_operation(AssumeBounded, x.get_type(), x=x,
                         lower_bound=lower_bound, upper_bound=upper_bound)


@dataclass(eq=False)
class MakeListView(Operation, opcode="make_list_view"):
    base_ptr: Var = operand()
    length: Var = operand()

    def generate_bytecode(self, ctx: "BytecodeContext"):
        ty = self.result_var.get_type()
        assert isinstance(ty, ListTy)
        item_size = get_list_item_repr_size_in_words(ty.item_type)
        tv_ty = tensor_view_typeid_for_list(ctx.type_table, item_size)
        pv_tile_shape = 1, get_list_partition_view_tile_size(item_size)
        # On padding value:
        # We intentionally choose to have padding_value Missing, such that
        # reading a list out of bound results in undefined memref
        # A safer choice is to have zero padding, which result in a zero shaped
        # memref which cannot be written to, but we do not want user to rely
        # on the consequence of this specific implementation.
        # Another alternative is to use a different encoding the shape/stride
        # such that zero padding will end up being FFFFF once read back. This way
        # out of bound access of list[array] will result in a memref at 0x0 with 0xFFFF
        # shape and stride, such that when there is accidental write to it, guarantees
        # illegal memory access.
        pv_ty = ctx.type_table.partition_view(pv_tile_shape, tv_ty, [0, 1],
                                              bc.PaddingValue.Missing)
        ptr = ctx.get_value(self.base_ptr)
        length = ctx.get_value(self.length)

def global_compiler_lock(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        with _compiler_lock:
            return func(*args, **kwargs)
    return wrapper


def _transform_ir(func_body: ir.Block,
                  bytecode_version: bc.BytecodeVersion,
                  param_constraints: Sequence[tuple[tuple[ir.Var, ...], ParameterConstraint]]):
    eliminate_assign_ops(func_body)
    dead_code_elimination_pass(func_body)
    dataflow_result = dataflow_analysis(func_body, param_constraints)

    if not CUDA_TILE_TESTING_DISABLE_DIV:
        add_divby_pass(func_body, dataflow_result)

    if not CUDA_TILE_TESTING_DISABLE_TOKEN_ORDER:
        token_order_pass(func_body, dataflow_result)

    rewrite_patterns(func_body)

    # Loop invariant code motion needs to run after the token order pass.
    # Otherwise, it may incorrectly hoist load operations out of the loop.
    hoist_loop_invariants(func_body)

    # For version < V_13_3, MakePartitionView must be emitted inline before its consumer.
    # Code motion may hoist it to an outer block; copy it back where needed.
    if bytecode_version < BytecodeVersion.V_13_3:
        unhoist_partition_views(func_body)

    split_loops(func_body)
    dead_code_elimination_pass(func_body)


@dataclass
class _KernelParameters:
    aggregate_vars: Sequence[ir.Var]
    nonconstant_flat_vars: Sequence[tuple[tuple[ir.Var, ...], ParameterConstraint]]


def _create_kernel_parameters(parameter_constraints: Sequence[ParameterConstraint],
                              parameter_annotations: Sequence[ParameterAnnotationNode],
                              parameter_names: Sequence[str],
                              parameter_locations: Sequence[Loc],
                              ir_ctx: ir.IRContext) -> _KernelParameters:
    nonconstant_flat_vars = []
    parameter_vars = tuple(ir_ctx.make_var(name, loc)
                           for name, loc in zip(parameter_names, parameter_locations, strict=True))

    for pos, (constraint, annotation, name, var) in enumerate(
            zip(parameter_constraints, parameter_annotations,
                parameter_names, parameter_vars, strict=True)):
        path = ParameterPath(name, ())
        _create_parameter(constraint, annotation, path, var, nonconstant_flat_vars)
    return _KernelParameters(parameter_vars, nonconstant_flat_vars)


@dataclass
class ParameterPath:
    name: str
    tuple_indices: tuple[int, ...]

    def tuple_item(self, index: int) -> "ParameterPath":
        return ParameterPath(self.name, self.tuple_indices + (index,))


def _create_parameter(
        constraint: ParameterConstraint,
        annotation: ParameterAnnotationNode,
        path: ParameterPath,
        var: ir.Var,
        nonconstant_flat_vars: list[tuple[tuple[ir.Var, ...], ParameterConstraint]]
):
    if isinstance(annotation, LeafAnnotationNode):
        annotation.validate()

        if annotation.array is not None and not isinstance(constraint, ArrayConstraint):
            raise _make_constraint_error("ArrayAnnotation/IndexedWithInt64 can only be applied"
                                         " to an array or a list-of-array parameter.", path)

        if annotation.list is not None and not isinstance(constraint, ListConstraint):
            raise _make_constraint_error("ArrayAnnotation/IndexedWithInt64 can only be applied"
                                         " to an array or a list-of-array parameter.", path)

        if annotation.scalar is not None and not isinstance(constraint, ScalarConstraint):
            raise _make_constraint_error(
                "ScalarAnnotation/ScalarInt64 can only be applied"
                " to a non-constant scalar parameter.", path)

    if isinstance(constraint, TupleConstraint):
        if isinstance(annotation, LeafAnnotationNode):
            item_nodes = [annotation] * len(constraint.items)
        elif isinstance(annotation, HomogeneousTupleNode):
            item_nodes = [annotation.each] * len(constraint.items)
        elif isinstance(annotation, HeterogeneousTupleNode):
            if len(annotation.items) != len(constraint.items):
                raise _make_constraint_error(
                        f"Received a tuple of length {len(constraint.items)}"
                        f" but the annotation implies length {len(annotation.items)}.",
                        path)
            item_nodes = annotation.items
        else:
            assert False

        item_vars = []
        for i, (item, node) in enumerate(zip(constraint.items, item_nodes, strict=True)):
            item_var = var.ctx.make_var(var.name + f"_{i}", var.loc)
            _create_parameter(item, node, path.tuple_item(i), item_var, nonconstant_flat_vars)
            item_vars.append(item_var)
        build_tuple(item_vars, result_var=var)
        return

    if not isinstance(annotation, LeafAnnotationNode):
        raise _make_constraint_error("Non-tuple parameter is annotated as a tuple.", path)

    if annotation.constant and not isinstance(constraint, ConstantConstraint):

